{
  "name": "express-tailwind-app",
  "version": "0.1.0",
  "private": true,
  "scripts": {
    "build": "tsc -p tsconfig.json && npm run build:css",
    "build:css": "tailwindcss -c tailwind.config.js -i src/styles/input.css -o public/styles.css --minify",
    "start": "npm run build && node dist/server.js",
    "test": "npm run build && mocha \"tests/**/*.test.js\""
  },
  "dependencies": {
    "express": "^4.19.2"
  },
  "devDependencies": {
    "@types/express": "^4.17.21",
    "@types/node": "^20.11.30",
    "autoprefixer": "^10.4.19",
    "chai": "^4.3.10",
    "mocha": "^10.4.0",
    "postcss": "^8.4.38",
    "supertest": "^6.3.3",
    "tailwindcss": "^3.4.10",
    "typescript": "^5.4.3"
  }
}

import express from 'express';
import path from 'path';

const app = express();

// Serve static assets from the public directory
const publicDir = path.join(__dirname, '..', 'public');
app.use(express.static(publicDir));

// Explicitly serve index.html at root
app.get('/', (_req, res) => {
  res.sendFile(path.join(publicDir, 'index.html'));
});

export default app;

import app from './app';

const PORT = Number(process.env.PORT) || 3000;

app.listen(PORT, () => {
  console.log(`Server listening on http://localhost:${PORT}`);
});

@tailwind base;
@tailwind components;
@tailwind utilities;

/* Custom styles to verify Tailwind build output and apply app styling */
.app-title { @apply text-4xl font-bold text-blue-600; }
.app-container { @apply text-center p-6 bg-white rounded-lg shadow; }
.body-bg { @apply min-h-screen bg-gray-100 flex items-center justify-center; }

const request = require('supertest');
const { expect } = require('chai');
const app = require('../dist/app').default;

describe('Express Tailwind App', function () {
  it('serves index.html with link to built styles.css', async function () {
    const res = await request(app).get('/');
    expect(res.status).to.equal(200);
    expect(res.text).to.include('Hello World');
    expect(res.text).to.match(/<link[^>]+href=["']\/styles\.css["']/);
  });

  it('serves built Tailwind CSS at /styles.css', async function () {
    const res = await request(app).get('/styles.css');
    expect(res.status).to.equal(200);
    expect(res.type).to.include('css');
    expect(res.text).to.include('.app-title');
  });
});
